const input = $input.first().json;

const execution = input.execution || {};
const workflow = input.workflow || {};
const trigger = input.trigger || {};
const error = execution.error || trigger.error || input.error || {};

const errorMessage = error.message || input.message || 'Unknown error message';
const errorStack = error.stack || '';
const lastNodeExecuted =
	execution.lastNodeExecuted ||
	trigger.name ||
	input.lastNodeExecuted ||
	'Unknown node';

const workflowName = workflow.name || input.workflowName || 'Unknown workflow';
const workflowId = workflow.id || input.workflowId || 'unknown-workflow-id';

const executionId = execution.id || 'not-saved';
const executionUrl = execution.url || null;
const retryOf = execution.retryOf || '';
const mode = execution.mode || trigger.mode || 'unknown';

const timestamp = new Date().toISOString();

return [
	{
		json: {
			workflow_name: workflowName,
			workflow_id: workflowId,
			execution_id: executionId,
			execution_url: executionUrl,
			retry_of: retryOf,
			error_node: lastNodeExecuted,
			error_message: errorMessage,
			error_stack: errorStack,
			execution_mode: mode,
			error_timestamp: timestamp,

			notion_database_id: input.notion_database_id,
			slack_channel_id: input.slack_channel_id,
			minimum_slack_severity: input.minimum_slack_severity,
			default_incident_status: input.default_incident_status,
			resolved_incident_status: input.resolved_incident_status,
			template_owner_note: input.template_owner_note,
		},
	},
];

const item = $input.first().json;

const text = [
	item.error_message || '',
	item.error_stack || '',
	item.error_node || '',
	item.workflow_name || '',
].join(' ').toLowerCase();

let errorCategory = 'Unknown error';
let severity = 'Medium';
let suggestedFix = 'Review the failed execution, inspect the node input/output, and check recent workflow changes.';

if (/401|403|unauthorized|forbidden|invalid credential|credential|oauth|token|api key|authentication/.test(text)) {
	errorCategory = 'Credential/auth error';
	severity = 'High';
	suggestedFix = 'Check the credential used by the failed node. Refresh OAuth credentials, verify API keys, and confirm the app connection still has permission.';
} else if (/429|rate limit|quota|too many requests|usage limit/.test(text)) {
	errorCategory = 'API rate limit';
	severity = 'High';
	suggestedFix = 'Check API rate limits, reduce execution frequency, add wait/retry logic, or upgrade the API plan if usage is legitimate.';
} else if (/timeout|etimedout|econnreset|network|socket hang up|dns|enotfound/.test(text)) {
	errorCategory = 'Timeout/network error';
	severity = 'Medium';
	suggestedFix = 'Check the external service status, increase timeout settings if available, and add retry logic for unstable API calls.';
} else if (/undefined|null|cannot read|missing|required field|no data|empty|not found/.test(text)) {
	errorCategory = 'Missing data';
	severity = 'Medium';
	suggestedFix = 'Inspect the previous node output. Add IF checks or default values before this node to handle missing fields safely.';
} else if (/400|bad request|validation|invalid parameter|invalid request/.test(text)) {
	errorCategory = 'Bad request';
	severity = 'Medium';
	suggestedFix = 'Check the request body, required fields, data types, and endpoint documentation for the failed API call.';
} else if (/500|502|503|504|server error|service unavailable|bad gateway/.test(text)) {
	errorCategory = 'Server/API failure';
	severity = 'High';
	suggestedFix = 'The external service may be down or unstable. Check service status and add retry/backoff handling.';
} else if (/syntaxerror|referenceerror|typeerror|expression|code node|function/.test(text)) {
	errorCategory = 'Expression/code error';
	severity = 'Medium';
	suggestedFix = 'Check expressions and Code node logic. Verify node names, field paths, and returned item structure.';
}

if (/payment|invoice|customer|production|order|webhook/.test(text) && severity === 'Medium') {
	severity = 'High';
}

if (/critical|security|data loss|failed payment|refund|blocked/.test(text)) {
	severity = 'Critical';
}

return [
	{
		json: {
			...item,
			error_category: errorCategory,
			severity,
			suggested_fix: suggestedFix,
		},
	},
];

const item = $input.first().json;

const cleanMessage = String(item.error_message || 'Unknown error')
	.replace(/\s+/g, ' ')
	.trim();

const shortMessage = cleanMessage.slice(0, 140);

const fingerprint = [
	item.workflow_id,
	item.error_node,
	item.error_category,
	cleanMessage.slice(0, 120),
]
	.join('|')
	.toLowerCase()
	.replace(/\s+/g, ' ')
	.trim();

const incidentTitle = `[${item.severity}] ${item.workflow_name} failed at ${item.error_node}`;

const slackMessage =
`🚨 *n8n workflow error detected*

*Severity:* ${item.severity}
*Category:* ${item.error_category}
*Workflow:* ${item.workflow_name}
*Failed node:* ${item.error_node}
*Execution ID:* ${item.execution_id}

*Error message:*
${shortMessage}

*Suggested fix:*
${item.suggested_fix}

${item.execution_url ? `*Execution URL:* ${item.execution_url}` : '*Execution URL:* Not available'}`;

return [
	{
		json: {
			...item,
			fingerprint,
			incident_title: incidentTitle,
			short_error_message: shortMessage,
			slack_message: slackMessage,
			first_seen: item.error_timestamp,
			last_seen: item.error_timestamp,
			occurrences: 1,
		},
	},
];

const existing = $input.first().json;
const incident = $('Build Incident Info').first().json;

let currentOccurrences = 1;

if (existing.properties?.Occurrences?.number !== undefined) {
	currentOccurrences = existing.properties.Occurrences.number;
} else if (existing.Occurrences !== undefined) {
	currentOccurrences = Number(existing.Occurrences) || 1;
}

const newOccurrences = currentOccurrences + 1;

return [
	{
		json: {
			...incident,
			notion_page_id: existing.id,
			occurrences: newOccurrences,
			is_new_incident: false,
		},
	},
];

const items = $input.all().map(item => item.json).filter(item => item.id);

if (items.length === 0) {
	return [
		{
			json: {
				send_digest: false,
				digest_message: 'No open n8n incidents found.',
			},
		},
	];
}

const severityCounts = {
	Critical: 0,
	High: 0,
	Medium: 0,
	Low: 0,
	Unknown: 0,
};

const lines = [];

for (const item of items.slice(0, 10)) {
	const props = item.properties || {};

	const title =
		props.Incident?.title?.[0]?.plain_text ||
		item.Incident ||
		'Untitled incident';

	const severity =
		props.Severity?.select?.name ||
		item.Severity ||
		'Unknown';

	const occurrences =
		props.Occurrences?.number ||
		item.Occurrences ||
		1;

	if (severityCounts[severity] !== undefined) {
		severityCounts[severity]++;
	} else {
		severityCounts.Unknown++;
	}

	lines.push(`• [${severity}] ${title} — ${occurrences} occurrence(s)`);
}

const digestMessage =
`📊 *Daily n8n error digest*

*Open incidents:* ${items.length}

*Severity breakdown:*
Critical: ${severityCounts.Critical}
High: ${severityCounts.High}
Medium: ${severityCounts.Medium}
Low: ${severityCounts.Low}

*Top incidents:*
${lines.join('\n')}

Review Notion for full incident details.`;

return [
	{
		json: {
			send_digest: true,
			digest_message: digestMessage,
		},
	},
];
